B.PN=new A.U(B.eW,"See the transformation",null,null,B.qM,null)
B.B=new A.oE(1,"rule")
B.QV=new A.U(B.B,"Formation Rule","**Active:** Subject + **verb** + object\n**Passive:** Object + **be** + past participle (+ by + agent)\n\n**Tense mapping:**\n\u2022 Simple Present \u2192 is/are + V3\n\u2022 Simple Past \u2192 was/were + V3\n\u2022 Must/Should \u2192 must/should + be + V3\n\u2022 Has/Have \u2192 has/have + been + V3",null,null,null)
B.ad=new A.oE(2,"examples")
B.Ky=new A.aF(u.d,"Hidrolik pompa, motor taraf\u0131ndan di\u015fli kutusu arac\u0131l\u0131\u011f\u0131yla \xe7al\u0131\u015ft\u0131r\u0131l\u0131r.","is driven")
B.JZ=new A.aF("All maintenance tasks must be performed in accordance with the AMM.","T\xfcm bak\u0131m g\xf6revleri AMM'ye uygun \u015fekilde ger\xe7ekle\u015ftirilmelidir.","must be performed")
B.KW=new A.aF("The fuel filter is replaced every 500 flight hours.","Yak\u0131t filtresi her 500 u\xe7u\u015f saatinde de\u011fi\u015ftirilir.","is replaced")
B.K4=new A.aF("Warning notices must be placed in the cockpit before maintenance.","Bak\u0131mdan \xf6nce kokpite uyar\u0131 levhalar\u0131 yerle\u015ftirilmelidir.","must be placed")
B.Wr=s([B.Ky,B.JZ,B.KW,B.K4],t.l)
B.Pm=new A.U(B.ad,"Aviation Examples",null,B.Wr,null,null)
B.ae=new A.oE(5,"tip")
B.Pn=new A.U(B.ae,"\u2708\ufe0f Exam Tip",'In multiple-choice questions, look for clues:\n\u2022 If the subject is a **thing** (not a person), passive is likely correct.\n\u2022 "\u2026\u2026\u2026\u2026 by the engine" \u2192 passive form needed.\n\u2022 Modal verbs + passive: **must be + past participle** is the most common pattern in aviation maintenance English.',null,null,null)
