B.Pk=new A.U(B.ad,"Sample ATIS Passage",null,B.Xs,null,null)
B.PV=new A.U(B.ae,"\u2708\ufe0f Reading Strategy",'For ATIS-type reading questions:\n\u2022 The **ATIS letter** changes every 30\u201360 minutes \u2014 questions may ask "what does Bravo indicate?"\n\u2022 **Runway in use** may differ for arrivals and departures\n\u2022 **Transition level** = lowest usable flight level above the transition altitude\n\u2022 **Special notices** at the end often contain the detail that is tested\n\u2022 Questions often ask: "According to the ATIS, which runway is available for\u2026?" \u2014 read carefully',null,null,null)
B.Wg=s(["18L","36R","18R","Both 18L and 18R"],t.s)
B.a38=new A.ab(-190,B.ax,620,"According to the ATIS, which runway is currently available for arrivals?",B.Wg,2,B.L,null,null,null)
