B.P0=new A.U(B.ac,"Accident reports use precise legal and technical language","ICAO Annex 13 accident investigation reports are among the most linguistically demanding documents in aviation. They combine legal precision, passive constructions, technical accuracy, and causal analysis in a single text.\n\nTranslation questions from these reports require understanding both the technical meaning and the legal implications of each phrase.",null,null,null)
B.Qp=new A.U(B.B,"\u26a0\ufe0f Causal Language",'**Probable cause** \u2014 the primary factor judged to have produced the accident\n**Contributing factor** \u2014 a condition that increased risk but was not the primary cause\n**Causal factor** \u2014 any element in the cause chain\n\nCausal verbs and phrases:\n\u2022 "**led to**" = caused/resulted in (direct chain)\n\u2022 "**attributed to**" = judged as the cause\n\u2022 "**resulted in**" = produced this outcome\n\u2022 "**was a factor in**" = contributed but not sole cause\n\u2022 "**was consistent with**" = evidence matches this explanation',null,null,null)
B.Q5=new A.U(B.B,"\ud83d\udccb Investigation Findings Language",'"The investigation **found** that\u2026" \u2192 formal finding\n"Evidence **indicated** that\u2026" \u2192 supported but not proven\n"**It could not be determined** whether\u2026" \u2192 insufficient evidence\n"The crew **failed to**\u2026" \u2192 did not perform required action\n"**Contrary to** the standard operating procedure\u2026" \u2192 SOP violation\n"The accident **is survivable** / **was not survivable**" \u2192 survivability finding\n"**Safety recommendation**" \u2192 formal advisory to prevent recurrence',null,null,null)
B.Le=new A.aF("The probable cause of the accident was the crew's failure to monitor fuel quantity.","Kazan\u0131n muhtemel nedeni, ekibin yak\u0131t miktar\u0131n\u0131 izlememesiydi.","probable cause")
B.KP=new A.aF("It could not be determined whether the crew had received the updated weather information.","Ekibin g\xfcncellenmi\u015f hava durumu bilgisini al\u0131p almad\u0131\u011f\u0131 belirlenemedi.","It could not be determined")
B.Lc=new A.aF("The investigation attributed the loss of situational awareness to crew fatigue and inadequate CRM.","Soru\u015fturma, durum fark\u0131ndal\u0131\u011f\u0131n\u0131n kayb\u0131n\u0131 m\xfcrettebat yorgunlu\u011funa ve yetersiz EKY'ye ba\u011flad\u0131.","attributed to")
B.XG=s([B.Le,B.KP,B.Lc],t.l)
B.Pu=new A.U(B.ad,"Report Passage Examples",null,B.XG,null,null)
B.QD=new A.U(B.ae,"\u2708\ufe0f Translation Exam Strategy",'For accident report translation questions:\n\u2022 "**Probable cause**" \u2260 "possible cause" \u2014 it is the MOST LIKELY established cause\n\u2022 "**Contributing factor**" \u2260 "main reason" \u2014 it is a secondary, exacerbating condition\n\u2022 "**Crew failed to**" = they did not do something required \u2014 not necessarily negligence\n\u2022 "**It could not be determined**" = insufficient evidence \u2014 do NOT translate as "it is unknown"\n\u2022 "**Contrary to SOP**" = a procedure violation \u2014 always serious in reports',null,null,null)
